@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:wght@400;500;600;700&display=swap');
@import url('./styles/print.css');
@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --background: hsl(54, 40%, 96%);
  --foreground: hsl(215, 20%, 20%);
  --card: hsl(0, 0%, 100%);
  --card-foreground: hsl(215, 20%, 20%);
  --popover: hsl(0, 0%, 100%);
  --popover-foreground: hsl(215, 20%, 20%);
  --primary: hsl(158, 64%, 26%);
  --primary-foreground: hsl(0, 0%, 98%);
  --secondary: hsl(84, 55%, 45%);
  --secondary-foreground: hsl(0, 0%, 98%);
  --muted: hsl(54, 20%, 90%);
  --muted-foreground: hsl(215, 15%, 45%);
  --accent: hsl(25, 95%, 53%);
  --accent-foreground: hsl(0, 0%, 98%);
  --destructive: hsl(0, 84%, 60%);
  --destructive-foreground: hsl(0, 0%, 98%);
  --border: hsl(54, 20%, 85%);
  --input: hsl(54, 20%, 85%);
  --ring: hsl(158, 64%, 26%);
  --chart-1: hsl(158, 64%, 26%);
  --chart-2: hsl(84, 55%, 45%);
  --chart-3: hsl(25, 95%, 53%);
  --chart-4: hsl(203, 88%, 53%);
  --chart-5: hsl(341, 75%, 51%);
  --sidebar: hsl(0, 0%, 100%);
  --sidebar-foreground: hsl(215, 20%, 20%);
  --sidebar-primary: hsl(158, 64%, 26%);
  --sidebar-primary-foreground: hsl(0, 0%, 98%);
  --sidebar-accent: hsl(54, 20%, 90%);
  --sidebar-accent-foreground: hsl(158, 64%, 26%);
  --sidebar-border: hsl(54, 20%, 85%);
  --sidebar-ring: hsl(158, 64%, 26%);

  /* Semantic surface tokens for elevation hierarchy */
  --surface-1: hsl(0, 0%, 99%);
  --surface-2: hsl(54, 30%, 98%);
  --surface-3: hsl(54, 40%, 99%);

  /* Brand gradient tokens */
  --gradient-brand-start: hsl(158, 64%, 26%);
  --gradient-brand-end: hsl(84, 55%, 45%);

  --font-sans: 'Inter', system-ui, -apple-system, sans-serif;
  --font-serif: 'Playfair Display', serif;
  --font-mono: Menlo, monospace;
  --radius: 0.75rem;
}

.dark {
  --background: hsl(215, 20%, 8%);
  --foreground: hsl(54, 20%, 90%);
  --card: hsl(215, 15%, 12%);
  --card-foreground: hsl(54, 20%, 90%);
  --popover: hsl(215, 15%, 12%);
  --popover-foreground: hsl(54, 20%, 90%);
  --primary: hsl(158, 64%, 35%);
  --primary-foreground: hsl(0, 0%, 98%);
  --secondary: hsl(84, 55%, 55%);
  --secondary-foreground: hsl(0, 0%, 98%);
  --muted: hsl(215, 15%, 18%);
  --muted-foreground: hsl(215, 10%, 65%);
  --accent: hsl(25, 95%, 63%);
  --accent-foreground: hsl(0, 0%, 98%);
  --destructive: hsl(0, 84%, 70%);
  --destructive-foreground: hsl(0, 0%, 98%);
  --border: hsl(215, 15%, 25%);
  --input: hsl(215, 15%, 25%);
  --ring: hsl(158, 64%, 35%);
  --sidebar: hsl(215, 15%, 12%);
  --sidebar-foreground: hsl(54, 20%, 90%);
  --sidebar-primary: hsl(158, 64%, 35%);
  --sidebar-primary-foreground: hsl(0, 0%, 98%);
  --sidebar-accent: hsl(215, 15%, 18%);
  --sidebar-accent-foreground: hsl(158, 64%, 35%);
  --sidebar-border: hsl(215, 15%, 25%);
  --sidebar-ring: hsl(158, 64%, 35%);

  /* Semantic surface tokens for elevation hierarchy (dark mode) */
  --surface-1: hsl(215, 15%, 15%);
  --surface-2: hsl(215, 15%, 18%);
  --surface-3: hsl(215, 15%, 22%);

  /* Brand gradient tokens (dark mode) */
  --gradient-brand-start: hsl(158, 64%, 35%);
  --gradient-brand-end: hsl(84, 55%, 55%);
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
    line-height: 1.6;
  }

  /* Improved spacing hierarchy */
  .section-padding {
    @apply py-16 px-4 sm:px-6 lg:px-8;
  }

  .section-padding-sm {
    @apply py-8 px-4 sm:px-6 lg:px-8;
  }

  .section-padding-lg {
    @apply py-24 px-4 sm:px-6 lg:px-8;
  }

  .container-max {
    @apply max-w-7xl mx-auto;
  }

  .container-content {
    @apply max-w-4xl mx-auto;
  }

  .container-narrow {
    @apply max-w-2xl mx-auto;
  }

  /* Enhanced contrast sections */
  .section-elevated {
    @apply bg-card shadow-sm border border-border;
  }

  .section-contrast {
    background-color: hsl(var(--muted) / 0.2);
  }

  .dark .section-contrast {
    background-color: hsl(var(--muted) / 0.05);
  }

  .section-accent {
    background-color: hsl(var(--primary) / 0.05);
    @apply border-l-4 border-primary;
  }

  .dark .section-accent {
    background-color: hsl(var(--primary) / 0.1);
  }

  .section-subtle {
    background-color: hsl(var(--muted) / 0.1);
  }

  .dark .section-subtle {
    background-color: hsl(var(--muted) / 0.05);
  }

  .section-alternate {
    background-color: hsl(var(--muted) / 0.3);
  }

  .dark .section-alternate {
    background-color: hsl(var(--muted) / 0.1);
  }

  /* Consistent section background utilities */
  .section-bg-primary {
    @apply bg-background;
  }

  .section-bg-secondary {
    background-color: hsl(var(--muted) / 0.2);
  }

  .dark .section-bg-secondary {
    background-color: hsl(var(--muted) / 0.05);
  }

  .section-bg-tertiary {
    background-color: hsl(var(--surface-2) / 0.5);
  }

  .dark .section-bg-tertiary {
    background-color: hsl(var(--surface-2) / 0.5);
  }

  .section-bg-quaternary {
    background: linear-gradient(to bottom, hsl(var(--background)), hsl(var(--surface-2) / 0.5), hsl(var(--background)));
  }

  .dark .section-bg-quaternary {
    background: linear-gradient(to bottom, hsl(var(--background)), hsl(var(--surface-2) / 0.5), hsl(var(--background)));
  }

  .section-bg-accent {
    background: linear-gradient(to bottom, hsl(var(--surface-1) / 0.3), hsl(var(--surface-3) / 0.2));
  }

  .dark .section-bg-accent {
    background: linear-gradient(to bottom, hsl(var(--surface-1) / 0.3), hsl(var(--surface-3) / 0.5));
  }

  .section-bg-muted {
    background-color: hsl(var(--muted) / 0.1);
  }

  .dark .section-bg-muted {
    background-color: hsl(var(--muted) / 0.05);
  }

  /* Card spacing improvements */
  .card-spacing {
    @apply p-6 space-y-4;
  }

  .card-spacing-sm {
    @apply p-4 space-y-3;
  }

  .card-spacing-lg {
    @apply p-8 space-y-6;
  }

  /* Form spacing */
  .form-spacing {
    @apply space-y-6;
  }

  .form-group {
    @apply space-y-2;
  }

  .form-grid {
    @apply grid grid-cols-1 gap-6 sm:grid-cols-2;
  }

  /* Button spacing */
  .button-group {
    @apply flex gap-3 flex-wrap;
  }

  .button-group-sm {
    @apply flex gap-2 flex-wrap;
  }

  /* Production mobile optimizations */
  @media (max-width: 768px) {
    .container {
      @apply px-3;
    }

    .button-group {
      @apply gap-2;
    }

    /* Mobile typography scaling */
    h1, .h1 { font-size: 30px !important; }
    h2, .h2 { font-size: 24px !important; }
    h3, .h3 { font-size: 20px !important; }
    h4, .h4 { font-size: 18px !important; }
    h5, .h5 { font-size: 16px !important; }
    h6, .h6 { font-size: 14px !important; }

    .lead { font-size: 18px !important; }
    body, p { font-size: 16px !important; }
  }

  /* Text spacing */
  .text-content {
    @apply space-y-4 leading-relaxed;
  }

  .text-content h1 {
    @apply mb-6 mt-0;
  }

  .text-content h2 {
    @apply mb-4 mt-8 first:mt-0;
  }

  .text-content h3 {
    @apply mb-3 mt-6 first:mt-0;
  }

  .text-content p {
    @apply mb-4 last:mb-0;
  }

  /* List improvements */
  .list-spaced {
    @apply space-y-3;
  }

  .list-spaced-sm {
    @apply space-y-2;
  }

  /* Navigation improvements */
  .nav-spacing {
    @apply px-4 sm:px-6 lg:px-8 py-4;
  }

  /* Footer improvements */
  .footer-spacing {
    @apply py-12 px-4 sm:px-6 lg:px-8;
  }

  /* Typography hierarchy - consistent sizing */
  h1, .h1 { 
    font-size: 38px !important; 
    font-weight: bold !important; 
    line-height: 1.1 !important; 
  }

  h2, .h2 { 
    font-size: 28px !important; 
    font-weight: 600 !important; 
    line-height: 1.2 !important; 
  }

  h3, .h3 { 
    font-size: 22px !important; 
    font-weight: 600 !important; 
    line-height: 1.3 !important; 
  }

  h4, .h4 { 
    font-size: 20px !important; 
    font-weight: 600 !important; 
    line-height: 1.4 !important; 
  }

  h5, .h5 { 
    font-size: 18px !important; 
    font-weight: 500 !important; 
    line-height: 1.5 !important; 
  }

  h6, .h6 { 
    font-size: 16px !important; 
    font-weight: 500 !important; 
    line-height: 1.5 !important; 
  }

  /* Body text */
  body, p, .body { 
    font-size: 16px !important; 
    line-height: 1.6 !important; 
  }

  /* Utility classes for consistent text sizing */
  .text-body { font-size: 16px !important; }
  .lead { font-size: 20px !important; font-weight: 400 !important; }
  small, .text-small { font-size: 14px !important; }
  .text-xs { font-size: 12px !important; }

  /* Print typography hierarchy - matches web hierarchy */
  @media print {
    h1, .h1 { font-size: 28pt !important; font-weight: bold !important; line-height: 1.1 !important; }
    h2, .h2 { font-size: 21pt !important; font-weight: 600 !important; line-height: 1.2 !important; }
    h3, .h3 { font-size: 16pt !important; font-weight: 600 !important; line-height: 1.3 !important; }
    h4, .h4 { font-size: 15pt !important; font-weight: 600 !important; line-height: 1.4 !important; }
    h5, .h5 { font-size: 13pt !important; font-weight: 500 !important; line-height: 1.5 !important; }
    h6, .h6 { font-size: 12pt !important; font-weight: 500 !important; line-height: 1.5 !important; }
    p, body { font-size: 12pt !important; }
    small { font-size: 10pt !important; }
  }
}

.memorial-card {
  transition: all 0.3s ease;
  @apply shadow-sm hover:shadow-md;
}

.memorial-card:hover {
  transform: translateY(-2px);
}

/* Enhanced contrast for better accessibility using surface tokens */
.high-contrast {
  background-color: hsl(var(--card));
  color: hsl(var(--card-foreground));
}

.medium-contrast {
  background-color: hsl(var(--surface-1));
  color: hsl(var(--foreground));
}

.low-contrast {
  background-color: hsl(var(--surface-2));
  color: hsl(var(--muted-foreground));
}

/* Improved focus states */
.focus-visible {
  @apply focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 focus-visible:ring-offset-background;
}

/* Gentle animations for a calming experience */
@keyframes gentle-float {
  0%, 100% { transform: translateY(0px) rotate(0deg); }
  25% { transform: translateY(-8px) rotate(1deg); }
  50% { transform: translateY(-15px) rotate(0deg); }
  75% { transform: translateY(-8px) rotate(-1deg); }
}

@keyframes soft-pulse {
  0%, 100% { opacity: 0.8; transform: scale(1); }
  50% { opacity: 1; transform: scale(1.05); }
}

@keyframes fade-in-up {
  from {
    opacity: 0;
    transform: translateY(40px) scale(0.95);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}

@keyframes glow-pulse {
  0%, 100% { box-shadow: 0 0 20px hsl(var(--primary) / 0.3); }
  50% { box-shadow: 0 0 40px hsl(var(--primary) / 0.6), 0 0 80px hsl(var(--primary) / 0.3); }
}

@keyframes float-rotate {
  0%, 100% { transform: translateY(0px) rotate(0deg); }
  33% { transform: translateY(-10px) rotate(2deg); }
  66% { transform: translateY(-5px) rotate(-1deg); }
}

.animate-gentle-float {
  animation: gentle-float 8s ease-in-out infinite;
}

.animate-soft-pulse {
  animation: soft-pulse 4s ease-in-out infinite;
}

.animate-fade-in-up {
  animation: fade-in-up 0.8s cubic-bezier(0.4, 0, 0.2, 1);
}

.animate-shimmer {
  background: linear-gradient(90deg, transparent, hsl(var(--foreground) / 0.1), transparent);
  background-size: 200% 100%;
  animation: shimmer 2s infinite;
}

.animate-glow-pulse {
  animation: glow-pulse 3s ease-in-out infinite;
}

.animate-float-rotate {
  animation: float-rotate 10s ease-in-out infinite;
}

/* Glass morphism effects */
.glass {
  background: hsl(var(--card) / 0.8);
  backdrop-filter: blur(10px);
  border: 1px solid hsl(var(--border) / 0.5);
}

.glass-dark {
  background: hsl(var(--popover) / 0.8);
  backdrop-filter: blur(10px);
  border: 1px solid hsl(var(--border) / 0.3);
}

/* Smooth transitions for interactive elements */
.smooth-hover {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.smooth-hover:hover {
  transform: translateY(-2px);
}

/* Brand gradient backgrounds using design tokens */
.gradient-brand {
  background: linear-gradient(135deg, var(--gradient-brand-start) 0%, var(--gradient-brand-end) 100%);
}

.gradient-brand-subtle {
  background: linear-gradient(135deg, color-mix(in srgb, var(--gradient-brand-start) 10%, transparent) 0%, color-mix(in srgb, var(--gradient-brand-end) 10%, transparent) 100%);
}

.gradient-accent {
  background: linear-gradient(135deg, hsl(var(--primary)) 0%, hsl(var(--accent)) 100%);
}

@media (max-width: 640px) {
  .hero-text {
    font-size: 1.875rem;
    line-height: 1.2;
  }

  .section-padding {
    @apply py-12 px-4;
  }

  .section-padding-lg {
    @apply py-16 px-4;
  }
}

@media (min-width: 641px) and (max-width: 768px) {
  .hero-text {
    font-size: 2.25rem;
    line-height: 1.2;
  }
}

