    return () => {
      clearSlideshowTimer();
    };
  }, [slideshowActive, slideshowPlaying, startSlideshowTimer, clearSlideshowTimer]);

  // Keyboard event handlers for slideshow
  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (!lightboxOpen) return;

      switch (event.code) {
        case 'ArrowRight':
        case 'ArrowDown':
          event.preventDefault();
          nextPhoto();
          break;
        case 'ArrowLeft':
        case 'ArrowUp':
          event.preventDefault();
          prevPhoto();
          break;
        case 'Space':
          event.preventDefault();
          if (slideshowActive) {
            if (slideshowPlaying) {
              pauseSlideshow();
            } else {
              resumeSlideshow();
            }
          }
          break;
        case 'Escape':
          event.preventDefault();
          if (slideshowActive) {
            stopSlideshow();
          } else {
            setLightboxOpen(false);
          }
          break;
      }
    };

    if (lightboxOpen) {
      document.addEventListener('keydown', handleKeyDown);
      return () => {
        document.removeEventListener('keydown', handleKeyDown);
      };
    }
  }, [lightboxOpen, slideshowActive, slideshowPlaying, nextPhoto, prevPhoto, pauseSlideshow, resumeSlideshow, stopSlideshow]);

  // Clean up timer on unmount
  useEffect(() => {
