import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation, useQuery } from "@tanstack/react-query";
import { z } from "zod";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Separator } from "@/components/ui/separator";
import { ServiceEventsEditor } from "@/components/service-events-editor";
import { OrderOfServiceCover } from "@/components/order-of-service-cover";
import { OrderOfServiceTimeline } from "@/components/order-of-service-timeline";
import type { DigitalOrderOfService, OrderOfServiceEvent } from "@shared/schema";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { 
  Save, 
  Eye, 
  EyeOff,
  Palette, 
  Calendar, 
  Clock, 
  MapPin, 
  User, 
  FileText,
  Camera,
  Loader2,
  Globe,
  Lock
} from "lucide-react";

interface OrderOfServiceFormProps {
  memorial: {
    id: string;
    firstName: string;
    lastName: string;
  };
  initialData?: DigitalOrderOfService;
  onSave?: (orderOfService: DigitalOrderOfService) => void;
  onCancel?: () => void;
}

// Enhanced form schema with proper validation
const formSchema = z.object({
  title: z.string().min(1, "Title is required").max(100, "Title must be 100 characters or less"),
  theme: z.enum(["classic", "modern", "elegant"]),
  fontFamily: z.enum(["serif", "sans-serif", "script"]),
  status: z.enum(["draft", "published"]),
  privacy: z.enum(["public", "private"]),
  coverPhotoUrl: z.string().url("Please enter a valid URL").optional().or(z.literal("")),
  tributeQuote: z.string().max(500, "Quote must be 500 characters or less").optional(),
  serviceDate: z.string().regex(/^\d{4}-\d{2}-\d{2}$/, "Please enter a valid date (YYYY-MM-DD)").optional().or(z.literal("")),
  serviceTime: z.string().regex(/^(1[0-2]|0?[1-9]):[0-5][0-9]\s?(AM|PM|am|pm)$|^([01]?[0-9]|2[0-3]):[0-5][0-9]$/, "Please enter a valid time (e.g., 2:00 PM or 14:00)").optional().or(z.literal("")),
  venue: z.string().max(200, "Venue must be 200 characters or less").optional(),
  officiant: z.string().max(100, "Officiant name must be 100 characters or less").optional()
});

type FormData = z.infer<typeof formSchema>;

const themes = [
  { value: 'classic', label: 'Classic', description: 'Traditional and timeless' },
  { value: 'modern', label: 'Modern', description: 'Clean and contemporary' },
  { value: 'elegant', label: 'Elegant', description: 'Warm and sophisticated' }
];

const fontFamilies = [
  { value: 'serif', label: 'Serif', description: 'Traditional and formal' },
  { value: 'sans-serif', label: 'Sans Serif', description: 'Clean and modern' },
  { value: 'script', label: 'Script', description: 'Elegant handwriting style' }
];

export function OrderOfServiceForm({
  memorial,
  initialData,
  onSave,
  onCancel
}: OrderOfServiceFormProps) {
  const { toast } = useToast();
  const [isPreviewMode, setIsPreviewMode] = useState(false);
  const [events, setEvents] = useState<OrderOfServiceEvent[]>([]);
  const [previewData, setPreviewData] = useState<any>(null);

  // Initialize form FIRST before using it
  const form = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      title: initialData?.title || "Celebration of Life",
      theme: (initialData?.theme as "classic" | "modern" | "elegant") || "classic",
      fontFamily: (initialData?.fontFamily as "serif" | "sans-serif" | "script") || "serif",
      status: (initialData?.status as "draft" | "published") || "draft",
      privacy: (initialData?.privacy as "public" | "private") || "public",
      coverPhotoUrl: initialData?.coverPhotoUrl || "",
      tributeQuote: initialData?.tributeQuote || "",
      serviceDate: initialData?.serviceDate ? new Date(initialData.serviceDate).toISOString().split('T')[0] : "",
      serviceTime: initialData?.serviceTime || "",
      venue: initialData?.venue || "",
      officiant: initialData?.officiant || ""
    }
  });

  // Fetch events if editing existing Order of Service
  const { data: existingEvents } = useQuery({
    queryKey: ['/api/order-of-service', initialData?.id, 'events'],
    enabled: !!initialData?.id
  });

  // Update events when data loads
  useEffect(() => {
    if (existingEvents && Array.isArray(existingEvents)) {
      setEvents(existingEvents);
    } else if (initialData?.events && Array.isArray(initialData.events)) {
      setEvents(initialData.events);
    }
  }, [existingEvents, initialData?.events]);

  // Update preview data when form values change
  const watchedValues = form.watch();
  useEffect(() => {
    setPreviewData({
      ...watchedValues,
      events
    });
  }, [watchedValues, events]);

  const createMutation = useMutation({
    mutationFn: async (data: FormData) => {
      const payload = {
        memorialId: memorial.id,
        ...data,
        // Convert empty strings to null for backend
        coverPhotoUrl: data.coverPhotoUrl || null,
        tributeQuote: data.tributeQuote || null,
        serviceDate: data.serviceDate || null,
        serviceTime: data.serviceTime || null,
        venue: data.venue || null,
        officiant: data.officiant || null
      };
      return apiRequest('POST', `/api/memorials/${memorial.id}/order-of-service`, payload);
    },
    onSuccess: (orderOfService: any) => {
      toast({
        title: "Order of Service created!",
        description: "Your Order of Service has been created successfully.",
      });
      queryClient.invalidateQueries({ queryKey: ['/api/memorials', memorial.id] });
      onSave?.(orderOfService);
    },
    onError: (error: any) => {
      toast({
        title: "Failed to create Order of Service",
        description: error.message || "Something went wrong. Please try again.",
        variant: "destructive",
      });
    }
  });

  const updateMutation = useMutation({
    mutationFn: async (data: FormData) => {
      const payload = {
        ...data,
        // Convert empty strings to null for backend
        coverPhotoUrl: data.coverPhotoUrl || null,
        tributeQuote: data.tributeQuote || null,
        serviceDate: data.serviceDate || null,
        serviceTime: data.serviceTime || null,
        venue: data.venue || null,
        officiant: data.officiant || null
      };
      return apiRequest('PATCH', `/api/order-of-service/${initialData?.id}`, payload);
    },
    onSuccess: (orderOfService: any) => {
      toast({
        title: "Order of Service updated!",
        description: "Your changes have been saved successfully.",
      });
      queryClient.invalidateQueries({ queryKey: ['/api/order-of-service', initialData?.id] });
      onSave?.(orderOfService);
    },
    onError: (error: any) => {
      toast({
        title: "Failed to update Order of Service",
        description: error.message || "Something went wrong. Please try again.",
        variant: "destructive",
      });
    }
  });

  const onSubmit = (data: FormData) => {
    if (initialData) {
      updateMutation.mutate(data);
    } else {
      createMutation.mutate(data);
    }
  };

  const isLoading = createMutation.isPending || updateMutation.isPending;

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-900 dark:text-slate-100">
            {initialData ? 'Edit' : 'Create'} Order of Service
          </h1>
          <p className="text-slate-600 dark:text-slate-400 mt-1">
            For {memorial.firstName} {memorial.lastName}'s memorial
          </p>
        </div>
        <div className="flex items-center space-x-2">
          <Button
            variant={isPreviewMode ? "default" : "outline"}
            onClick={() => setIsPreviewMode(!isPreviewMode)}
            data-testid="toggle-preview-button"
          >
            {isPreviewMode ? <EyeOff className="h-4 w-4 mr-2" /> : <Eye className="h-4 w-4 mr-2" />}
            {isPreviewMode ? 'Edit Mode' : 'Preview Mode'}
          </Button>
        </div>
      </div>

      {isPreviewMode ? (
        /* Live Preview Mode */
        <div className="space-y-8">
          {previewData && (
            <div className="grid grid-cols-1 gap-8">
              {/* Preview Cover */}
              <OrderOfServiceCover
                orderOfService={{
                  ...initialData,
                  ...previewData,
                  id: initialData?.id || 'preview',
                  memorialId: memorial.id,
                  createdAt: initialData?.createdAt || new Date(),
                  updatedAt: new Date(),
                  viewCount: 0,
                  downloadCount: 0,
                  createdBy: null
                }}
                memorial={{
                  firstName: memorial.firstName,
                  lastName: memorial.lastName,
                  dateOfBirth: new Date().toISOString(),
                  dateOfPassing: new Date().toISOString(),
                  profilePhotoUrl: previewData.coverPhotoUrl || undefined,
                  memorialMessage: previewData.tributeQuote || undefined
                }}
                theme={previewData.theme as 'classic' | 'modern' | 'elegant'}
              />

              {/* Preview Timeline */}
              {events.length > 0 && (
                <OrderOfServiceTimeline
                  events={events}
                  theme={previewData.theme as 'classic' | 'modern' | 'elegant'}
                />
              )}
            </div>
          )}
        </div>
      ) : (
        /* Edit Mode */
        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Main Form */}
            <div className="lg:col-span-2 space-y-6">
              {/* Basic Information */}
              <Card data-testid="basic-info-section">
                <CardHeader>
                  <CardTitle className="flex items-center space-x-2">
                    <FileText className="h-5 w-5" />
                    <span>Basic Information</span>
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <FormField
                    control={form.control}
                    name="title"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Title</FormLabel>
                        <FormControl>
                          <Input 
                            {...field} 
                            placeholder="Celebration of Life"
                            data-testid="title-input"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="tributeQuote"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Tribute Quote (Optional)</FormLabel>
                        <FormControl>
                          <Textarea
                            {...field}
                            placeholder="A meaningful quote or verse to honor their memory..."
                            rows={3}
                            data-testid="tribute-quote-input"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="coverPhotoUrl"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Cover Photo URL (Optional)</FormLabel>
                        <FormControl>
                          <div className="flex items-center space-x-2">
                            <Camera className="h-4 w-4 text-slate-400" />
                            <Input
                              {...field}
                              placeholder="https://example.com/photo.jpg"
                              data-testid="cover-photo-input"
                            />
                          </div>
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </CardContent>
              </Card>

              {/* Service Details */}
              <Card data-testid="service-details-section">
                <CardHeader>
                  <CardTitle className="flex items-center space-x-2">
                    <Calendar className="h-5 w-5" />
                    <span>Service Details</span>
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="serviceDate"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Service Date</FormLabel>
                          <FormControl>
                            <Input
                              {...field}
                              type="date"
                              data-testid="service-date-input"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="serviceTime"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Service Time</FormLabel>
                          <FormControl>
                            <div className="flex items-center space-x-2">
                              <Clock className="h-4 w-4 text-slate-400" />
                              <Input
                                {...field}
                                placeholder="e.g., 2:00 PM"
                                data-testid="service-time-input"
                              />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <FormField
                    control={form.control}
                    name="venue"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Venue</FormLabel>
                        <FormControl>
                          <div className="flex items-center space-x-2">
                            <MapPin className="h-4 w-4 text-slate-400" />
                            <Input
                              {...field}
                              placeholder="Church name and address"
                              data-testid="venue-input"
                            />
                          </div>
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="officiant"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Officiant</FormLabel>
                        <FormControl>
                          <div className="flex items-center space-x-2">
                            <User className="h-4 w-4 text-slate-400" />
                            <Input
                              {...field}
                              placeholder="Pastor, Reverend, or service leader name"
                              data-testid="officiant-input"
                            />
                          </div>
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </CardContent>
              </Card>

              {/* Service Events Section */}
              {initialData && (
                <ServiceEventsEditor
                  orderOfServiceId={initialData.id}
                  events={events}
                  onEventsChange={setEvents}
                  isEditable={true}
                />
              )}
            </div>

            {/* Settings Sidebar */}
            <div className="space-y-6">
              {/* Design Settings */}
              <Card data-testid="design-settings-section">
                <CardHeader>
                  <CardTitle className="flex items-center space-x-2">
                    <Palette className="h-5 w-5" />
                    <span>Design</span>
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <FormField
                    control={form.control}
                    name="theme"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Theme</FormLabel>
                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                          <FormControl>
                            <SelectTrigger data-testid="theme-select">
                              <SelectValue placeholder="Select theme" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {themes.map(theme => (
                              <SelectItem key={theme.value} value={theme.value}>
                                <div>
                                  <div className="font-medium">{theme.label}</div>
                                  <div className="text-xs text-slate-500">{theme.description}</div>
                                </div>
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="fontFamily"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Font Family</FormLabel>
                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                          <FormControl>
                            <SelectTrigger data-testid="font-family-select">
                              <SelectValue placeholder="Select font" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {fontFamilies.map(font => (
                              <SelectItem key={font.value} value={font.value}>
                                <div>
                                  <div className="font-medium">{font.label}</div>
                                  <div className="text-xs text-slate-500">{font.description}</div>
                                </div>
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </CardContent>
              </Card>

              {/* Publishing Settings */}
              <Card data-testid="publishing-settings-section">
                <CardHeader>
                  <CardTitle>Publishing</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <FormField
                    control={form.control}
                    name="status"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Status</FormLabel>
                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                          <FormControl>
                            <SelectTrigger data-testid="status-select">
                              <SelectValue placeholder="Select status" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="draft">
                              <div className="flex items-center space-x-2">
                                <FileText className="h-4 w-4" />
                                <div>
                                  <div className="font-medium">Draft</div>
                                  <div className="text-xs text-slate-500">Not visible to others</div>
                                </div>
                              </div>
                            </SelectItem>
                            <SelectItem value="published">
                              <div className="flex items-center space-x-2">
                                <Globe className="h-4 w-4" />
                                <div>
                                  <div className="font-medium">Published</div>
                                  <div className="text-xs text-slate-500">Visible to others</div>
                                </div>
                              </div>
                            </SelectItem>
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="privacy"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Privacy</FormLabel>
                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                          <FormControl>
                            <SelectTrigger data-testid="privacy-select">
                              <SelectValue placeholder="Select privacy" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="public">
                              <div className="flex items-center space-x-2">
                                <Globe className="h-4 w-4" />
                                <span>Public - Anyone can view</span>
                              </div>
                            </SelectItem>
                            <SelectItem value="private">
                              <div className="flex items-center space-x-2">
                                <Lock className="h-4 w-4" />
                                <span>Private - Only you can view</span>
                              </div>
                            </SelectItem>
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </CardContent>
              </Card>

              {/* Action Buttons */}
              <div className="space-y-3">
                <Button
                  type="submit"
                  className="w-full"
                  disabled={isLoading}
                  data-testid="save-order-of-service-button"
                >
                  {isLoading ? (
                    <>
                      <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                      Saving...
                    </>
                  ) : (
                    <>
                      <Save className="h-4 w-4 mr-2" />
                      {initialData ? 'Update' : 'Create'} Order of Service
                    </>
                  )}
                </Button>

                {onCancel && (
                  <Button
                    type="button"
                    variant="outline"
                    className="w-full"
                    onClick={onCancel}
                    disabled={isLoading}
                    data-testid="cancel-button"
                  >
                    Cancel
                  </Button>
                )}
              </div>
            </div>
          </div>
        </form>
      </Form>
      )}

      {/* Service Events for new Order of Service */}
      {!initialData && !isPreviewMode && (
        <Card className="p-6">
          <div className="text-center space-y-4">
            <FileText className="h-12 w-12 mx-auto text-slate-400" />
            <div>
              <h3 className="text-lg font-semibold text-slate-700 dark:text-slate-300 mb-2">
                Service Events
              </h3>
              <p className="text-slate-500 dark:text-slate-400">
                Create your Order of Service first, then add service events like prayers, hymns, and readings.
              </p>
            </div>
          </div>
        </Card>
      )}
    </div>
  );
}

client/src/components/order-of-service-t.content:
import { Card, CardContent } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Clock, Music, Book, Heart, Users, Star, Edit3, Trash2, GripVertical } from "lucide-react";
import type { OrderOfServiceEvent } from "@shared/schema";

interface OrderOfServiceTimelineProps {
  events: OrderOfServiceEvent[];
  theme?: 'classic' | 'modern' | 'elegant';
  isEditable?: boolean;
  onEditEvent?: (event: OrderOfServiceEvent) => void;
  onDeleteEvent?: (eventId: string) => void;
  onReorderEvents?: (eventIds: string[]) => void;
  className?: string;
}

const eventTypeIcons = {
  'opening_prayer': Book,
  'hymn': Music,
  'reading': Book,
  'eulogy': Heart,
  'reflection': Star,
  'music': Music,
  'tribute': Heart,
  'closing_prayer': Book,
  'other': Users
};

const eventTypeLabels = {
  'opening_prayer': 'Opening Prayer',
  'hymn': 'Hymn',
  'reading': 'Scripture Reading',
  'eulogy': 'Eulogy',
  'reflection': 'Reflection',
  'music': 'Musical Selection',
  'tribute': 'Tribute',
  'closing_prayer': 'Closing Prayer',
  'other': 'Other'
};

export function OrderOfServiceTimeline({
  events,
  theme = 'classic',
  isEditable = false,
  onEditEvent,
  onDeleteEvent,
  onReorderEvents,
  className
}: OrderOfServiceTimelineProps) {
  const themeClasses = {
    classic: {
      container: "bg-surface-1/50 border-border",
      eventCard: "bg-card border-border",
      timeline: "bg-border",
      timelineNode: "bg-muted-foreground border-card",
      text: {
        primary: "text-foreground",
        secondary: "text-muted-foreground",
        muted: "text-muted-foreground/70"
      }
    },
    modern: {
      container: "bg-chart-4/10 border-chart-4/30",
      eventCard: "bg-card border-chart-4/30",
      timeline: "bg-chart-4/50",
      timelineNode: "bg-chart-4 border-card",
      text: {
        primary: "text-foreground",
        secondary: "text-chart-4",
        muted: "text-chart-4/80"
      }
    },
    elegant: {
      container: "bg-accent/10 border-accent/30",
      eventCard: "bg-card border-accent/30",
      timeline: "bg-accent/50",
      timelineNode: "bg-accent border-card",
      text: {
        primary: "text-foreground",
        secondary: "text-accent",
        muted: "text-accent/80"
      }
    }
  };

  const currentTheme = themeClasses[theme];

  if (events.length === 0) {
    return (
      <Card className={`${currentTheme.container} p-8 ${className}`} data-testid="empty-timeline">
        <div className="text-center space-y-4">
          <Users className={`h-12 w-12 mx-auto ${currentTheme.text.muted} opacity-50`} />
          <div>
            <h3 className={`text-lg font-semibold ${currentTheme.text.primary}`}>
              No Events Added Yet
            </h3>
            <p className={`text-sm ${currentTheme.text.muted} mt-1`}>
              {isEditable ? 'Add events to create your Order of Service timeline' : 'This Order of Service has no events listed'}
            </p>
          </div>
        </div>
      </Card>
    );
  }

  return (
    <Card className={`${currentTheme.container} p-6 ${className}`} data-testid="service-timeline">
      <div className="space-y-6">
        <div className="text-center space-y-2">
          <h2 className={`text-xl md:text-2xl font-serif ${currentTheme.text.primary} font-semibold`}>
            Order of Service
          </h2>
          <Separator className="opacity-30" />
        </div>

        <div className="relative">
          {/* Timeline line */}
          <div className={`absolute left-6 top-0 bottom-0 w-0.5 ${currentTheme.timeline}`} />

          <div className="space-y-6">
            {events.map((event, index) => {
              const IconComponent = eventTypeIcons[event.eventType as keyof typeof eventTypeIcons] || Users;
              const isLast = index === events.length - 1;

              return (
                <div key={event.id} className="relative flex items-start space-x-6 group">
                  {/* Timeline node */}
                  <div className={`
                    flex items-center justify-center w-12 h-12 rounded-full 
                    ${currentTheme.timelineNode} border-4 shadow-sm z-10
                  `}>
                    <IconComponent className="h-5 w-5 text-white" />
                  </div>

                  {/* Event content */}
                  <Card className={`
                    flex-1 ${currentTheme.eventCard} shadow-sm hover:shadow-md transition-shadow
                    ${isEditable ? 'cursor-pointer hover:bg-opacity-80' : ''}
                  `}>
                    <CardContent className="p-4">
                      <div className="flex items-start justify-between">
                        <div className="flex-1 min-w-0" data-testid={`event-${event.id}`}>
                          {/* Event header */}
                          <div className="flex items-center space-x-3 mb-2">
                            <h3 className={`font-semibold ${currentTheme.text.primary}`}>
                              {event.title}
                            </h3>
                            <Badge variant="outline" className="text-xs">
                              {eventTypeLabels[event.eventType as keyof typeof eventTypeLabels]}
                            </Badge>
                          </div>

                          {/* Event details */}
                          <div className="space-y-2">
                            {event.speaker && (
                              <p className={`text-sm ${currentTheme.text.secondary}`}>
                                <span className="font-medium">Speaker:</span> {event.speaker}
                              </p>
                            )}

                            {event.duration && (
                              <div className="flex items-center space-x-1">
                                <Clock className={`h-3 w-3 ${currentTheme.text.muted}`} />
                                <span className={`text-xs ${currentTheme.text.muted}`}>
                                  {event.duration}
                                </span>
                              </div>
                            )}

                            {event.description && (
                              <p className={`text-sm ${currentTheme.text.secondary} leading-relaxed`}>
                                {event.description}
                              </p>
                            )}

                            {event.content && (
                              <div className={`text-sm ${currentTheme.text.muted} mt-3 p-2 bg-surface-1/50 rounded`}>
                                <p className="italic">{event.content}</p>
                              </div>
                            )}
                          </div>
                        </div>

                        {/* Edit controls */}
                        {isEditable && (
                          <div className="flex items-center space-x-1 ml-4">
                            <Button
                              variant="ghost"
                              size="sm"
                              className="h-8 w-8 p-0 opacity-0 group-hover:opacity-100 transition-opacity"
                              onClick={() => onEditEvent?.(event)}
                              data-testid={`edit-event-${event.id}`}
                            >
                              <Edit3 className="h-3 w-3" />
                              <span className="sr-only">Edit event</span>
                            </Button>
                            <Button
                              variant="ghost"
                              size="sm"
                              className="h-8 w-8 p-0 text-destructive hover:text-destructive/80 opacity-0 group-hover:opacity-100 transition-opacity"
                              onClick={() => onDeleteEvent?.(event.id)}
                              data-testid={`delete-event-${event.id}`}
                            >
                              <Trash2 className="h-3 w-3" />
                              <span className="sr-only">Delete event</span>
                            </Button>
                            {onReorderEvents && (
                              <Button
                                variant="ghost"
                                size="sm"
                                className="h-8 w-8 p-0 opacity-0 group-hover:opacity-100 transition-opacity cursor-grab active:cursor-grabbing"
                                data-testid={`reorder-event-${event.id}`}
                              >
                                <GripVertical className="h-3 w-3" />
                                <span className="sr-only">Reorder event</span>
                              </Button>
                            )}
                          </div>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                </div>
              );
            })}
          </div>
        </div>

        {/* Footer with event count */}
        <div className="text-center pt-4 border-t border-border">
          <p className={`text-xs ${currentTheme.text.muted}`}>
            {events.length} {events.length === 1 ? 'event' : 'events'} in this service
          </p>
        </div>
      </div>
    </Card>
  );
}

client/src/components/service-events-edi.content:
import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Badge } from "@/components/ui/badge";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import type { OrderOfServiceEvent } from "@shared/schema";
import { 
  Plus, 
  Edit3, 
  Trash2, 
  GripVertical, 
  Music, 
  Book, 
  Heart, 
  Users, 
  Star,
  Clock,
  User,
  FileText,
  Save
} from "lucide-react";

interface ServiceEventsEditorProps {
  orderOfServiceId: string;
  events: OrderOfServiceEvent[];
  onEventsChange?: (events: OrderOfServiceEvent[]) => void;
  isEditable?: boolean;
}

const eventSchema = z.object({
  title: z.string().min(1, "Title is required"),
  eventType: z.enum([
    "opening_prayer", "hymn", "reading", "eulogy", "reflection", 
    "music", "tribute", "closing_prayer", "other"
  ]),
  description: z.string().optional(),
  speaker: z.string().optional(),
  duration: z.string().optional(),
  content: z.string().optional()
});

type EventFormData = z.infer<typeof eventSchema>;

const eventTypes = [
  { value: 'opening_prayer', label: 'Opening Prayer', icon: Book },
  { value: 'hymn', label: 'Hymn', icon: Music },
  { value: 'reading', label: 'Scripture Reading', icon: Book },
  { value: 'eulogy', label: 'Eulogy', icon: Heart },
  { value: 'reflection', label: 'Reflection', icon: Star },
  { value: 'music', label: 'Musical Selection', icon: Music },
  { value: 'tribute', label: 'Tribute', icon: Heart },
  { value: 'closing_prayer', label: 'Closing Prayer', icon: Book },
  { value: 'other', label: 'Other', icon: Users }
];

export function ServiceEventsEditor({ 
  orderOfServiceId, 
  events, 
  onEventsChange,
  isEditable = true 
}: ServiceEventsEditorProps) {
  const { toast } = useToast();
  const [isAddingEvent, setIsAddingEvent] = useState(false);
  const [editingEvent, setEditingEvent] = useState<OrderOfServiceEvent | null>(null);
  const [draggedEventId, setDraggedEventId] = useState<string | null>(null);

  const eventForm = useForm<EventFormData>({
    resolver: zodResolver(eventSchema),
    defaultValues: {
      title: "",
      eventType: "other",
      description: "",
      speaker: "",
      duration: "",
      content: ""
    }
  });

  // Create event mutation
  const createEventMutation = useMutation({
    mutationFn: async (data: EventFormData) => {
      const orderIndex = events.length; // Add at the end
      return apiRequest('POST', `/api/order-of-service/${orderOfServiceId}/events`, {
        ...data,
        orderIndex
      });
    },
    onSuccess: (newEvent: any) => {
      toast({
        title: "Event added!",
        description: "Service event has been added successfully.",
      });
      queryClient.invalidateQueries({ queryKey: ['/api/order-of-service', orderOfServiceId] });
      onEventsChange?.([...events, newEvent]);
      setIsAddingEvent(false);
      eventForm.reset();
    },
    onError: (error: any) => {
      toast({
        title: "Failed to add event",
        description: error.message || "Something went wrong. Please try again.",
        variant: "destructive",
      });
    }
  });

  // Update event mutation
  const updateEventMutation = useMutation({
    mutationFn: async (data: { id: string; updates: Partial<EventFormData> }) => {
      return apiRequest('PATCH', `/api/order-of-service-events/${data.id}`, data.updates);
    },
    onSuccess: (updatedEvent: any) => {
      toast({
        title: "Event updated!",
        description: "Service event has been updated successfully.",
      });
      queryClient.invalidateQueries({ queryKey: ['/api/order-of-service', orderOfServiceId] });
      const updatedEvents = events.map(event => 
        event.id === updatedEvent.id ? updatedEvent : event
      );
      onEventsChange?.(updatedEvents);
      setEditingEvent(null);
      eventForm.reset();
    },
    onError: (error: any) => {
      toast({
        title: "Failed to update event",
        description: error.message || "Something went wrong. Please try again.",
        variant: "destructive",
      });
    }
  });

  // Delete event mutation
  const deleteEventMutation = useMutation({
    mutationFn: async (eventId: string) => {
      return apiRequest('DELETE', `/api/order-of-service-events/${eventId}`);
    },
    onSuccess: (_: any, deletedEventId: string) => {
      toast({
        title: "Event deleted!",
        description: "Service event has been deleted successfully.",
      });
      queryClient.invalidateQueries({ queryKey: ['/api/order-of-service', orderOfServiceId] });
      const updatedEvents = events.filter(event => event.id !== deletedEventId);
      onEventsChange?.(updatedEvents);
    },
    onError: (error: any) => {
      toast({
        title: "Failed to delete event",
        description: error.message || "Something went wrong. Please try again.",
        variant: "destructive",
      });
    }
  });

  // Reorder events mutation
  const reorderEventsMutation = useMutation({
    mutationFn: async (eventIds: string[]) => {
      return apiRequest('PATCH', `/api/order-of-service/${orderOfServiceId}/events/reorder`, {
        eventIds
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/order-of-service', orderOfServiceId] });
    }
  });

  const handleAddEvent = () => {
    setEditingEvent(null);
    eventForm.reset({
      title: "",
      eventType: "other",
      description: "",
      speaker: "",
      duration: "",
      content: ""
    });
    setIsAddingEvent(true);
  };

  const handleEditEvent = (event: OrderOfServiceEvent) => {
    setIsAddingEvent(false);
    setEditingEvent(event);
    eventForm.reset({
      title: event.title,
      eventType: event.eventType as any,
      description: event.description || "",
      speaker: event.speaker || "",
      duration: event.duration || "",
      content: event.content || ""
    });
  };

  const handleDeleteEvent = (eventId: string) => {
    if (confirm('Are you sure you want to delete this event?')) {
      deleteEventMutation.mutate(eventId);
    }
  };

  const handleDragStart = (e: React.DragEvent, eventId: string) => {
    setDraggedEventId(eventId);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetEventId: string) => {
    e.preventDefault();

    if (!draggedEventId || draggedEventId === targetEventId) {
      setDraggedEventId(null);
      return;
    }

    const draggedIndex = events.findIndex(event => event.id === draggedEventId);
    const targetIndex = events.findIndex(event => event.id === targetEventId);

    if (draggedIndex === -1 || targetIndex === -1) return;

    // Reorder events array
    const reorderedEvents = [...events];
    const [draggedEvent] = reorderedEvents.splice(draggedIndex, 1);
    reorderedEvents.splice(targetIndex, 0, draggedEvent);

    // Update local state immediately
    onEventsChange?.(reorderedEvents);

    // Send to backend
    const eventIds = reorderedEvents.map(event => event.id);
    reorderEventsMutation.mutate(eventIds);

    setDraggedEventId(null);
  };

  const onSubmit = (data: EventFormData) => {
    if (editingEvent) {
      updateEventMutation.mutate({
        id: editingEvent.id,
        updates: data
      });
    } else {
      createEventMutation.mutate(data);
    }
  };

  const isLoading = createEventMutation.isPending || updateEventMutation.isPending || deleteEventMutation.isPending;

  return (
    <Card data-testid="service-events-editor">
      <CardHeader>
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center space-x-2">
            <FileText className="h-5 w-5" />
            <span>Service Events</span>
          </CardTitle>
          {isEditable && (
            <Button
              onClick={handleAddEvent}
              size="sm"
              data-testid="add-event-button"
            >
              <Plus className="h-4 w-4 mr-2" />
              Add Event
            </Button>
          )}
        </div>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Events List */}
        {events.length > 0 ? (
          <div className="space-y-2">
            {events.map((event, index) => {
              const eventType = eventTypes.find(type => type.value === event.eventType);
              const IconComponent = eventType?.icon || Users;

              return (
                <div
                  key={event.id}
                  draggable={isEditable}
                  onDragStart={(e) => handleDragStart(e, event.id)}
                  onDragOver={handleDragOver}
                  onDrop={(e) => handleDrop(e, event.id)}
                  className={`
                    p-4 border rounded-lg bg-white dark:bg-slate-800 
                    ${isEditable ? 'cursor-move hover:bg-slate-50 dark:hover:bg-slate-700' : ''}
                    ${draggedEventId === event.id ? 'opacity-50' : ''}
                  `}
                  data-testid={`event-item-${event.id}`}
                >
                  <div className="flex items-start justify-between">
                    <div className="flex items-start space-x-3 flex-1">
                      {isEditable && (
                        <GripVertical className="h-4 w-4 text-slate-400 mt-1 cursor-grab" />
                      )}
                      <div className="flex items-center justify-center w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-700">
                        <IconComponent className="h-4 w-4 text-slate-600 dark:text-slate-400" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center space-x-2 mb-1">
                          <h4 className="font-medium text-slate-900 dark:text-slate-100">
                            {event.title}
                          </h4>
                          <Badge variant="outline" className="text-xs">
                            {eventType?.label}
                          </Badge>
                          <span className="text-xs text-slate-500">#{index + 1}</span>
                        </div>
                        {event.description && (
                          <p className="text-sm text-slate-600 dark:text-slate-400 mb-1">
                            {event.description}
                          </p>
                        )}
                        <div className="flex items-center space-x-4 text-xs text-slate-500">
                          {event.speaker && (
                            <span className="flex items-center space-x-1">
                              <User className="h-3 w-3" />
                              <span>{event.speaker}</span>
                            </span>
                          )}
                          {event.duration && (
                            <span className="flex items-center space-x-1">
                              <Clock className="h-3 w-3" />
                              <span>{event.duration}</span>
                            </span>
                          )}
                        </div>
                      </div>
                    </div>

                    {isEditable && (
                      <div className="flex items-center space-x-1">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleEditEvent(event)}
                          data-testid={`edit-event-${event.id}`}
                        >
                          <Edit3 className="h-3 w-3" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          className="text-red-500 hover:text-red-700"
                          onClick={() => handleDeleteEvent(event.id)}
                          data-testid={`delete-event-${event.id}`}
                        >
                          <Trash2 className="h-3 w-3" />
                        </Button>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="text-center py-8 text-slate-500">
            <FileText className="h-12 w-12 mx-auto mb-4 opacity-50" />
            <p>No service events added yet.</p>
            {isEditable && (
              <p className="text-sm mt-1">Click "Add Event" to start building your program.</p>
            )}
          </div>
        )}

        {/* Add/Edit Event Dialog */}
        {isEditable && (
          <Dialog open={isAddingEvent || !!editingEvent} onOpenChange={(open) => {
            if (!open) {
              setIsAddingEvent(false);
              setEditingEvent(null);
              eventForm.reset();
            }
          }}>
            <DialogContent className="max-w-lg">
              <DialogHeader>
                <DialogTitle>
                  {editingEvent ? 'Edit Event' : 'Add Service Event'}
                </DialogTitle>
              </DialogHeader>

              <Form {...eventForm}>
                <form onSubmit={eventForm.handleSubmit(onSubmit)} className="space-y-4">
                  <FormField
                    control={eventForm.control}
                    name="title"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Event Title *</FormLabel>
                        <FormControl>
                          <Input 
                            {...field}
                            placeholder="e.g., Opening Prayer, Welcome Song"
                            data-testid="event-title-input"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={eventForm.control}
                    name="eventType"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Event Type</FormLabel>
                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                          <FormControl>
                            <SelectTrigger data-testid="event-type-select">
                              <SelectValue placeholder="Select event type" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {eventTypes.map(type => (
                              <SelectItem key={type.value} value={type.value}>
                                <div className="flex items-center space-x-2">
                                  <type.icon className="h-4 w-4" />
                                  <span>{type.label}</span>
                                </div>
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={eventForm.control}
                      name="speaker"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Speaker/Leader</FormLabel>
                          <FormControl>
                            <Input 
                              {...field}
                              placeholder="Optional"
                              data-testid="event-speaker-input"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={eventForm.control}
                      name="duration"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Duration</FormLabel>
                          <FormControl>
                            <Input 
                              {...field}
                              placeholder="e.g., 5 min"
                              data-testid="event-duration-input"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <FormField
                    control={eventForm.control}
                    name="description"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Description</FormLabel>
                        <FormControl>
                          <Textarea
                            {...field}
                            rows={2}
                            placeholder="Brief description or notes about this event..."
                            data-testid="event-description-input"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={eventForm.control}
                    name="content"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Content/Script</FormLabel>
                        <FormControl>
                          <Textarea
                            {...field}
                            rows={3}
                            placeholder="Prayer text, song lyrics, reading passage, or speech notes..."
                            data-testid="event-content-input"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <div className="flex space-x-2 pt-4">
                    <Button 
                      type="submit"
                      disabled={isLoading}
                      data-testid="save-event-button"
                    >
                      {isLoading && <Save className="h-4 w-4 mr-2 animate-spin" />}
                      {editingEvent ? 'Update Event' : 'Add Event'}
                    </Button>
                    <Button 
                      type="button"
                      variant="outline"
                      onClick={() => {
                        setIsAddingEvent(false);
                        setEditingEvent(null);
                        eventForm.reset();
                      }}
                      data-testid="cancel-event-button"
                    >
                      Cancel
                    </Button>
                  </div>
                </form>
              </Form>
            </DialogContent>
          </Dialog>
        )}
      </CardContent>
    </Card>
  );
}

