/* Print-specific styles for Order of Service */

@media print {
  /* Reset all margins and paddings for print */
  * {
    -webkit-print-color-adjust: exact !important;
    print-color-adjust: exact !important;
  }

  /* Page setup */
  @page {
    size: A4;
    margin: 0.5in;
    background: white;
  }

  /* Hide non-printable elements */
  .print\\:hidden,
  .print\\:hidden *,
  header,
  nav,
  .header,
  .navigation,
  .sticky,
  button:not(.print\\:block),
  .btn:not(.print\\:block),
  .toast,
  .dialog,
  .dropdown,
  .popover,
  .tooltip,
  [data-testid*="button"]:not(.print\\:block),
  [data-testid*="edit"]:not(.print\\:block),
  [data-testid*="delete"]:not(.print\\:block),
  [data-testid*="share"]:not(.print\\:block),
  [data-testid="back-button"],
  [data-testid="edit-button"],
  [data-testid="share-button"],
  [data-testid="download-print-button"],
  [data-testid="toggle-preview-button"],
  .edit-controls,
  .hover\\:opacity-100,
  .group-hover\\:opacity-100 {
    display: none !important;
    visibility: hidden !important;
  }

  /* Ensure content is visible */
  .print\\:block {
    display: block !important;
  }

  .print\\:inline {
    display: inline !important;
  }

  .print\\:flex {
    display: flex !important;
  }

  /* Page structure */
  body {
    font-family: 'Times New Roman', 'Libre Baskerville', Georgia, serif !important;
    font-size: 12pt !important;
    line-height: 1.4 !important;
    color: #000000 !important;
    background: white !important;
    -webkit-font-smoothing: antialiased;
  }

  /* Container adjustments */
  .container {
    max-width: none !important;
    width: 100% !important;
    margin: 0 !important;
    padding: 0 !important;
  }

  /* Order of Service Cover styling */
  [data-testid="order-of-service-cover"] {
    page-break-inside: avoid;
    margin-bottom: 0.5in !important;
    padding: 1in 0.75in !important;
    background: white !important;
    border: none !important;
    box-shadow: none !important;
  }

  /* Cover page typography */
  [data-testid="order-of-service-cover"] h1 {
    font-size: 20pt !important;
    font-weight: bold !important;
    color: #000000 !important;
    text-align: center !important;
    margin: 0.5in 0 0.3in 0 !important;
  }

  [data-testid="order-of-service-cover"] h2 {
    font-size: 18pt !important;
    font-weight: bold !important;
    color: #000000 !important;
    text-align: center !important;
    margin: 0.3in 0 !important;
  }

