          <div className="flex flex-col sm:flex-row gap-4 justify-center">
            <Button variant="outline" data-testid="button-contact-support">
              Contact Support
            </Button>
            <Button variant="outline" data-testid="button-schedule-call">
              Schedule a Call
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

